create schema if not exists valorapesquisa;
create extension if not exists pgcrypto;
create table if not exists valorapesquisa.organizations(id uuid primary key default gen_random_uuid(),name text not null,public_name text not null,slug text not null unique,document text,email text not null,phone text,status text not null default 'active',plan_code text not null default 'free',created_at timestamptz not null default now(),updated_at timestamptz,created_by uuid,updated_by uuid,is_deleted boolean not null default false);
create table if not exists valorapesquisa.users(id uuid primary key default gen_random_uuid(),organization_id uuid references valorapesquisa.organizations(id),name text not null,email text not null unique,password_hash text not null,role text not null check(role in ('admin_valora','empresa_admin','gestor_pesquisa','participante')),status text not null default 'active',phone text,last_login_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz,is_deleted boolean not null default false);
create table if not exists valorapesquisa.forms(id uuid primary key default gen_random_uuid(),organization_id uuid not null references valorapesquisa.organizations(id),title text not null,description text,status text not null default 'draft',created_at timestamptz not null default now(),updated_at timestamptz,is_deleted boolean not null default false);
create table if not exists valorapesquisa.questions(id uuid primary key default gen_random_uuid(),form_id uuid not null references valorapesquisa.forms(id),text text not null,type text not null check(type in ('scale','single_choice','multiple_choice','short_text')),position int not null,required boolean not null default false,weight numeric(10,2) not null default 1,max_score numeric(10,2) not null default 5);
create table if not exists valorapesquisa.question_options(id uuid primary key default gen_random_uuid(),question_id uuid not null references valorapesquisa.questions(id),text text not null,score numeric(10,2) not null default 0,position int not null default 0);
create table if not exists valorapesquisa.surveys(id uuid primary key default gen_random_uuid(),organization_id uuid not null references valorapesquisa.organizations(id),form_id uuid not null references valorapesquisa.forms(id),title text not null,description text,status text not null default 'draft' check(status in ('draft','published','paused','closed')),starts_at timestamptz,expires_at timestamptz,show_result boolean not null default true,allow_repeat boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz,is_deleted boolean not null default false);
create table if not exists valorapesquisa.survey_links(id uuid primary key default gen_random_uuid(),survey_id uuid not null references valorapesquisa.surveys(id),organization_id uuid not null references valorapesquisa.organizations(id),token_hash text not null,public_url text not null,status text not null default 'active',expires_at timestamptz,revoked_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz);
create table if not exists valorapesquisa.responses(id uuid primary key default gen_random_uuid(),organization_id uuid not null references valorapesquisa.organizations(id),survey_id uuid not null references valorapesquisa.surveys(id),form_id uuid not null references valorapesquisa.forms(id),participant_name text,participant_email text,status text not null default 'completed',completed_at timestamptz not null default now(),result_token_hash text not null,created_at timestamptz not null default now());
create table if not exists valorapesquisa.response_answers(id uuid primary key default gen_random_uuid(),response_id uuid not null references valorapesquisa.responses(id),question_id uuid not null references valorapesquisa.questions(id),answer_value text,answer_text text);
create table if not exists valorapesquisa.result_scores(id uuid primary key default gen_random_uuid(),response_id uuid not null references valorapesquisa.responses(id),total_score numeric(10,2) not null,max_score numeric(10,2) not null,percentage numeric(10,2) not null,normalized_5 numeric(10,2) not null,level text not null,result_json jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
create table if not exists valorapesquisa.audit_logs(id uuid primary key default gen_random_uuid(),organization_id uuid,user_id uuid,action text not null,entity text not null,entity_id uuid,correlation_id text not null,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
create index if not exists ix_users_org on valorapesquisa.users(organization_id); create index if not exists ix_forms_org on valorapesquisa.forms(organization_id); create index if not exists ix_surveys_org on valorapesquisa.surveys(organization_id); create index if not exists ix_audit_org on valorapesquisa.audit_logs(organization_id,created_at desc);
